/** @since 5.0 */
export interface ViewBaseEventTypes {
  /**
   * Fires when the view's size changes.
   *
   * @since 5.0
   * @see [MapView.size](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#size)
   * @see [MapView.height](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#height)
   * @see [MapView.width](https://developers.arcgis.com/javascript/latest/references/core/views/MapView/#width)
   */
  resize: ViewResizeEvent;
  /**
   * Fires after each layer in the map has a corresponding [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) created
   * and rendered in the view.
   *
   * @since 5.0
   * @see [View.whenLayerView()](https://developers.arcgis.com/javascript/latest/references/core/views/View/#whenLayerView)
   * @example
   * // This function fires each time a layer view is created for a layer in
   * // the map of the view.
   * view.on("layerview-create", function(event) {
   *   // The event contains the layer and its layer view that has just been
   *   // created. Here we check for the creation of a layer view for a layer with
   *   // a specific id, and log the layer view
   *   if (event.layer.id === "satellite") {
   *     // The LayerView for the desired layer
   *     console.log(event.layerView);
   *   }
   * });
   */
  "layerview-create": LayerViewCreateEvent;
  /**
   * Fires when an error occurs during the creation of a [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/)
   * after a layer has been added to the map.
   *
   * @since 5.0
   * @see [View.whenLayerView()](https://developers.arcgis.com/javascript/latest/references/core/views/View/#whenLayerView)
   * @example
   * // This function fires each time an error occurs during the creation of a layerview
   * view.on("layerview-create-error", function(event) {
   *   console.error("LayerView failed to create for layer with the id: ", event.layer.id);
   * });
   */
  "layerview-create-error": LayerViewCreateErrorEvent;
  /**
   * Fires after a [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) is destroyed and is
   * no longer rendered in the view. This happens for example when a layer is
   * removed from the map of the view.
   *
   * @since 5.0
   */
  "layerview-destroy": LayerViewDestroyEvent;
}

/** @since 5.0 */
export interface ViewEventTypes extends ViewBaseEventTypes {
  /**
   * Fires after a user clicks on the view. This event emits slightly slower than an
   * [View.@immediate-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-immediate-click) event to make sure that a [View.@double-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-double-click)
   * event isn't triggered instead. The [View.@immediate-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-immediate-click) event can be used
   * for responding to a click event without delay.
   *
   * @since 5.0
   * @see [Sample: Access features with hitTest](https://developers.arcgis.com/javascript/latest/sample-code/map-component-hittest/)
   * @example
   * view.on("click", function(event){
   *   // event is the event object returned after the event fires
   *
   *   // Prints the map coordinates of the clicked location
   *   console.log(event.mapPoint);
   * });
   * @example
   * // Set up a click event handler and retrieve the screen point
   * view.on("click", function(event) {
   *  // the hitTest() checks to see if any graphics in the view
   *  // intersect the given screen x, y coordinates
   *  view.hitTest(event)
   *   .then(getGraphics);
   * });
   * @example
   * view.on("click", function(event) {
   *  // you must overwrite default click-for-popup
   *  // behavior to display your own popup
   *  view.popupEnabled = false;
   *
   *  // Get the coordinates of the click on the view
   *  let lat = Math.round(event.mapPoint.latitude * 1000) / 1000;
   *  let lon = Math.round(event.mapPoint.longitude * 1000) / 1000;
   *
   *  view.popup.open({
   *    // Set the popup's title to the coordinates of the location
   *    title: "Reverse geocode: [" + lon + ", " + lat + "]",
   *    location: event.mapPoint // Set the location of the popup to the clicked location
   *    content: "This is a point of interest"  // content displayed in the popup
   *  });
   * });
   */
  click: ClickEvent;
  /**
   * Fires after double-clicking on the view.
   *
   * @since 5.0
   * @example
   * view.on("double-click", function(event) {
   *   // The event object contains the mapPoint and the screen coordinates of the location
   *   // that was clicked.
   *   console.log("screen point", event.x, event.y);
   *   console.log("map point", event.mapPoint);
   * });
   */
  "double-click": DoubleClickEvent;
  /**
   * Fires right after a user clicks on the view. In contrast to the [View.@click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-click) event,
   * the `immediate-click` event is emitted as soon as the user clicks on
   * the view, and is not inhibited by a [View.@double-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-double-click) event. This event
   * is useful for interactive experiences that require feedback without delay.
   *
   * @example
   * // Set up an immediate-click event handler and retrieve the screen point
   * view.on("immediate-click", function(event) {
   *  // the hitTest() checks to see if any graphics in the view
   *  // intersect the given screen x, y coordinates
   *  view.hitTest(event)
   *   .then(getGraphics);
   * });
   */
  "immediate-click": ImmediateClickEvent;
  /**
   * Is emitted after two consecutive [View.@immediate-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-immediate-click) events.
   * In contrast to [View.@double-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-double-click), an `immediate-double-click` cannot
   * be prevented by use of `stopPropagation` on the [View.@immediate-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-immediate-click)
   * event and can therefore be used to react to double-clicking independently of usage of the
   * [View.@immediate-click](https://developers.arcgis.com/javascript/latest/references/core/views/View/#event-immediate-click) event.
   */
  "immediate-double-click": ImmediateDoubleClickEvent;
  /**
   * Fires after holding either a mouse button or a single finger on the view for a short amount of time.
   *
   * @since 5.0
   * @example
   * view.on("hold", function(event) {
   *   // The event object contains the mapPoint and the screen coordinates of the location
   *   // that was clicked.
   *   console.log("hold at screen point", event.x, event.y);
   *   console.log("hold at map point", event.mapPoint);
   * });
   */
  hold: HoldEvent;
  /**
   * Fires during a pointer drag on the view.
   *
   * @since 5.0
   * @example
   * view.on("drag", function(event){
   *  // Print out the current state of the
   *  // drag event.
   *  console.log("drag state", event.action);
   * });
   */
  drag: DragEvent;
  /**
   * Fires after a keyboard key is pressed.
   *
   * @since 5.0
   * @example
   * // Zoom in when user clicks on "a" button
   * // Zoom out when user clicks on "s" button
   * view.on("key-down", function(event){
   *  console.log("key-down", event);
   *
   *  if (event.key === "a"){
   *    let zm = view.zoom + 1;
   *
   *    view.goTo({
   *      target: view.center,
   *      zoom: zm
   *    });
   *  }
   *  else if(event.key == "s"){
   *    let zm = view.zoom - 1;
   *
   *    view.goTo({
   *      target: view.center,
   *      zoom: zm
   *    });
   *  }
   * });
   */
  "key-down": KeyDownEvent;
  /**
   * Fires after a keyboard key is released.
   *
   * @since 5.0
   */
  "key-up": KeyUpEvent;
  /**
   * Fires after a mouse button is pressed, or a finger touches the display.
   *
   * @since 5.0
   */
  "pointer-down": PointerDownEvent;
  /**
   * Fires after the mouse or a finger on the display moves.
   *
   * @since 5.0
   * @example
   * // Fires `pointer-move` event when user clicks on "Shift"
   * // key and moves the pointer on the view.
   * view.on('pointer-move', ["Shift"], function(event){
   *   let point = view.toMap({x: event.x, y: event.y});
   *   bufferPoint(point);
   * });
   */
  "pointer-move": PointerMoveEvent;
  /**
   * Fires after a mouse button is released, or a display touch ends.
   *
   * @since 5.0
   */
  "pointer-up": PointerUpEvent;
  /**
   * Fires after a mouse cursor enters the view, or a display touch begins.
   *
   * @since 5.0
   */
  "pointer-enter": PointerEnterEvent;
  /**
   * Fires after a mouse cursor leaves the view, or a display touch ends.
   *
   * @since 5.0
   */
  "pointer-leave": PointerLeaveEvent;
  /**
   * Fires when a wheel button of a pointing device (typically a mouse) is scrolled on the view.
   *
   * @since 5.0
   * @example
   * view.on("mouse-wheel", function(event){
   *  // deltaY value is positive when wheel is scrolled up
   *  // and it is negative when wheel is scrolled down.
   *  console.log(event.deltaY);
   * });
   */
  "mouse-wheel": ViewMouseWheelEvent;
  /** Fires when browser focus is on the view. */
  focus: ViewFocusEvent;
  /** Fires when browser focus is moved away from the view. */
  blur: ViewBlurEvent;
  /**
   * Fires while the pointer is drag following a double-tap gesture on the view.
   *
   * @since 5.0
   * @example
   * view.on("double-tap-drag", (event) => {
   *   // Display the distance moved from the drag origin.
   *   console.log("x distance:", event.x, "y distance:", event.y);
   * });
   */
  "double-tap-drag": DoubleTapDragEvent;
  /**
   * Fires while the two pointers are dragged on the view.
   *
   * @since 5.0
   * @example
   * view.on("vertical-two-finger-drag", (event) => {
   *   // Display the distance moved vertically from the drag origin.
   *   console.log("y distance:", event.y);
   * });
   */
  "vertical-two-finger-drag": VerticalTwoFingerDragEvent;
}